package com.example.webhook.service;

import com.example.webhook.api.FetchResult;
import com.example.webhook.api.WebhookRequest;
import org.apache.hc.client5.http.classic.CloseableHttpClient;
import org.apache.hc.client5.http.classic.methods.HttpGet;
import org.apache.hc.client5.http.classic.methods.HttpUriRequestBase;
import org.apache.hc.client5.http.impl.classic.CloseableHttpResponse;
import org.apache.hc.core5.http.Header;
import org.apache.hc.core5.http.HttpEntity;
import org.apache.hc.core5.http.io.entity.EntityUtils;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.net.IDN;
import java.net.InetAddress;
import java.net.URI;
import java.util.*;
import java.util.regex.Pattern;

@Service
public class UrlFetchService {

    private static final Pattern IPV4_PRIVATE = Pattern.compile(
            "^(10\\..*|192\\.168\\..*|172\\.(1[6-9]|2\\d|3[0-1])\\..*)$"
    );

    private final CloseableHttpClient httpClient;
    private final int maxBytes;

    public UrlFetchService(CloseableHttpClient httpClient,
                           @Value("${webhook.fetch.max-bytes:1048576}") int maxBytes) {
        this.httpClient = httpClient;
        this.maxBytes = maxBytes;
    }

    public FetchResult fetch(WebhookRequest req) throws Exception {
        URI uri = validateAndNormalize(req.getUrl());

        String method = (req.getMethod() == null || req.getMethod().isBlank()) ? "GET" : req.getMethod().toUpperCase(Locale.ROOT);
        if (!method.equals("GET")) {
            throw new IllegalArgumentException("Only GET is supported");
        }

        HttpUriRequestBase request = new HttpGet(uri);

        if (req.getHeaders() != null) {
            for (Map.Entry<String, String> e : req.getHeaders().entrySet()) {
                String name = e.getKey();
                if (name == null) continue;
                String lower = name.toLowerCase(Locale.ROOT);
                if (lower.equals("host") || lower.equals("content-length") || lower.equals("connection")) continue;
                request.addHeader(name, e.getValue());
            }
        }

        try (CloseableHttpResponse response = httpClient.execute(request)) {
            int status = response.getCode();

            Map<String, List<String>> headers = new LinkedHashMap<>();
            for (Header h : response.getHeaders()) {
                headers.computeIfAbsent(h.getName(), k -> new ArrayList<>()).add(h.getValue());
            }

            String contentType = null;
            Header ct = response.getFirstHeader("Content-Type");
            if (ct != null) contentType = ct.getValue();

            HttpEntity entity = response.getEntity();
            byte[] body = entity != null ? EntityUtils.toByteArray(entity) : new byte[0];
            if (body.length > maxBytes) {
                body = Arrays.copyOf(body, maxBytes);
            }

            return new FetchResult(status, headers, contentType, body);
        }
    }

    private URI validateAndNormalize(String url) throws Exception {
        if (url == null || url.isBlank()) throw new IllegalArgumentException("url is required");
        URI uri = URI.create(url.trim());

        String scheme = uri.getScheme();
        if (scheme == null) throw new IllegalArgumentException("Invalid URL scheme");
        scheme = scheme.toLowerCase(Locale.ROOT);
        if (!scheme.equals("http") && !scheme.equals("https")) {
            throw new IllegalArgumentException("Only http/https are allowed");
        }

        String host = uri.getHost();
        if (host == null || host.isBlank()) throw new IllegalArgumentException("Host is required");

        String asciiHost = IDN.toASCII(host);
        InetAddress addr = InetAddress.getByName(asciiHost);
        if (addr.isAnyLocalAddress() || addr.isLoopbackAddress() || addr.isLinkLocalAddress() || addr.isSiteLocalAddress()) {
            throw new IllegalArgumentException("Private or local addresses are not allowed");
        }
        String hostAddress = addr.getHostAddress();
        if (hostAddress != null && IPV4_PRIVATE.matcher(hostAddress).matches()) {
            throw new IllegalArgumentException("Private addresses are not allowed");
        }

        int port = uri.getPort();
        if (port != -1 && (port < 1 || port > 65535)) throw new IllegalArgumentException("Invalid port");

        return new URI(
                scheme,
                uri.getUserInfo(),
                asciiHost,
                port,
                uri.getRawPath(),
                uri.getRawQuery(),
                uri.getRawFragment()
        );
    }
}

package com.example.webhook.web;

import com.example.webhook.api.FetchResult;
import com.example.webhook.api.WebhookRequest;
import com.example.webhook.service.UrlFetchService;
import jakarta.servlet.http.HttpServletRequest;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.util.MultiValueMap;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/webhook")
public class WebhookController {

    private final UrlFetchService fetchService;

    public WebhookController(UrlFetchService fetchService) {
        this.fetchService = fetchService;
    }

    @PostMapping(value = "/partner", consumes = MediaType.APPLICATION_JSON_VALUE)
    public ResponseEntity<byte[]> handlePartnerWebhook(@RequestBody WebhookRequest webhookRequest,
                                                       HttpServletRequest incoming) throws Exception {
        FetchResult result = fetchService.fetch(webhookRequest);

        HttpHeaders out = new HttpHeaders();
        if (result.getContentType() != null) {
            MediaType mt;
            try {
                mt = MediaType.parseMediaType(result.getContentType());
            } catch (Exception e) {
                mt = MediaType.APPLICATION_OCTET_STREAM;
            }
            out.setContentType(mt);
        } else {
            out.setContentType(MediaType.APPLICATION_OCTET_STREAM);
        }

        for (Map.Entry<String, List<String>> e : result.getHeaders().entrySet()) {
            String name = e.getKey();
            if (name == null) continue;
            String lower = name.toLowerCase();
            if (lower.equals("transfer-encoding") || lower.equals("content-length") || lower.equals("connection")) continue;
            for (String v : e.getValue()) {
                out.add(name, v);
            }
        }

        return ResponseEntity.status(result.getStatus()).headers(out).body(result.getBody());
    }
}

